package com.example.myapplication.viewmodels

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.myapplication.R
import com.example.myapplication.data.UserProfile
import com.example.myapplication.domain.model.BodyGoldenRatioResult
import com.example.myapplication.domain.model.PlanResult
import com.example.myapplication.domain.model.UserDayStatus
import com.example.myapplication.domain.gamification.ManageGamificationUseCase
import com.example.myapplication.domain.gamification.WorkoutCompletionResult
import com.example.myapplication.domain.auth.AuthStateRepository
import com.example.myapplication.domain.profile.UserProfileRepository
import com.example.myapplication.domain.model.BodyMeasurementEntry
import com.example.myapplication.domain.repository.BodyMeasurementsRepository
import com.example.myapplication.domain.usecase.CalculateBodyGoldenRatioUseCase
import com.example.myapplication.domain.usecase.GetBodyMetricsUseCase
import com.example.myapplication.domain.usecase.SaveBodyMeasurementsUseCase
import com.example.myapplication.domain.usecase.SwapPlanDaysUseCase
import com.example.myapplication.domain.usecase.UpdateBodyMetricsUseCase
import kotlinx.coroutines.Job
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharedFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asSharedFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.flatMapLatest
import kotlinx.coroutines.flow.flowOf
import kotlinx.coroutines.flow.receiveAsFlow
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch

/**
 * Faza 30.9 вҖ” Enkratni UI dogodki za BodyModul.
 *
 * Razlika od StateFlow:
 *   StateFlow  = trajno stanje (kateri zaslon je odprt, ali nalagamoвҖҰ)
 *   Channel    = enkratni dogodek (prikaЕҫi Snackbar, navigiraj, zapri dialog)
 *
 * Ne smeЕЎ shranjevati teh vrednosti v StateFlow вҖ” Snackbar bi se ob rotaciji zaslona
 * prikazal znova. Channel zagotavlja natanko en sprejem.
 */
sealed interface BodyUiEvent {
    /** Meritve so bile uspeЕЎno shranjene v Firestore. */
    data object SaveSuccess : BodyUiEvent
    /** Napaka med shranjevanjem вҖ” prikaЕҫi Snackbar z [message]. */
    data class Error(val message: String) : BodyUiEvent
}

/**
 * Faza 31.1 вҖ” Enoten UI state za Golden Ratio sekcijo.
 *
 * NadomeЕЎДҚa tri razprЕЎene StateFlow-e:
 *   bodyProfile: StateFlow<UserProfile?>     вҶ’ pokrit z Loading/Success
 *   goldenRatioResults: StateFlow<Result?>   вҶ’ Success.data
 *   isSaving: StateFlow<Boolean>             вҶ’ Success.isSaving
 *
 * Prednosti:
 *   вҖў Atomarni prehodi вҖ” UI nikoli ne vidi nedosledne kombinacije vrednosti
 *   вҖў Error.messageRes je Int (R.string.*) вҶ’ brez hardkodiranih nizov v VM
 *   вҖў Loading stanje prepreДҚuje vizualno utripanje ("flash of empty content")
 */
sealed interface GoldenRatioUiState {
    /** Profil se nalaga iz Firestore вҖ” pokaЕҫi CircularProgressIndicator. */
    data object Loading : GoldenRatioUiState

    /**
     * Profil naloЕҫen вҖ” pokaЕҫi celotni vmesnik z vnosi.
     * @param profileHeight  ViЕЎina iz profila (za prikaz in izraДҚun pas/viЕЎina razmerja)
     * @param data           Rezultat izraДҚuna; null dokler uporabnik ne vnese meritev
     * @param isSaving       true med Firestore batch write вҖ” gumb onemogoДҚen
     * @param inputErrorRes  Faza 31.2 вҖ” R.string.* ID inline validacijske napake vnosa;
     *                       null = vnos je veljaven ali prazen.
     *                       PrikaЕҫe se pod vnosnimi polji, ne zamenja celotnega zaslona.
     */
    data class Success(
        val profileHeight: Double?,
        val data: BodyGoldenRatioResult?,
        val isSaving: Boolean = false,
        val inputErrorRes: Int? = null
    ) : GoldenRatioUiState

    /**
     * Napaka pri inicializaciji zaslona (npr. izpad Firestore med nalaganjem profila).
     * NI namenjen validacijskim napakam vnosa вҖ” za to se uporablja [Success.inputErrorRes].
     * @param messageRes  ID string resursa (R.string.*) вҖ” lokalizabilen, brez Context v VM
     */
    data class Error(val messageRes: Int) : GoldenRatioUiState
}

/**
 * Faza 30.1 вҖ” Vhodni podatki za telesni Zlati Rez.
 * shoulderCm/waistCm = 0.0 pomeni: ni vnosa вҶ’ goldenRatioResults = null.
 */
data class BodyMeasurementsInput(
    val shoulderCm: Double = 0.0,
    val waistCm: Double    = 0.0,
    val hipCm: Double      = 0.0,
    val heightCm: Double   = 0.0  // fallback, ДҚe profil nima viЕЎine
)

data class Challenge(
    val id: String,
    val title: String,
    val description: String,
    val xpReward: Int = 100,
    val accepted: Boolean = false,
    val completed: Boolean = false,
    val iconRes: Int? = null
)

/**
 * UI stanje za Body Home zaslon.
 *
 * Faza 21: todayStatus je zdaj tipsko-varni [UserDayStatus] namesto String.
 */
data class BodyHomeUiState(
    val streakDays: Int = 0,
    val streakFreezes: Int = 0,
    val weeklyDone: Int = 0,
    val weeklyTarget: Int = 3,
    val planDay: Int = 1,
    val totalWorkoutsCompleted: Int = 0,
    val workoutsToday: Int = 0,
    val isWorkoutDoneToday: Boolean = false,
    val dailyKcal: Int = 0,
    val showCompletionAnimation: Boolean = false,
    val todayIsRest: Boolean = false,
    val outdoorSuggestion: String? = null,
    val errorMessage: String? = null,
    val isLoading: Boolean = false,
    /** Tipsko-varni status danaЕЎnjega dne вҖ” nadomeЕЎДҚa String "WORKOUT_DONE" itd. */
    val todayStatus: UserDayStatus = UserDayStatus.WORKOUT_PENDING,
    val challenges: List<Challenge> = listOf(
        Challenge("c1", "30 days sixpack", "Get a sixpack in 30 days. Perform core exercises daily.", 500),
        Challenge("c2", "30 days pushups", "Improve your pushups in 30 days. Do 50 pushups/day.", 300),
        Challenge("c3", "Mobility week", "Increase your ROM in 7 days. Stretch every morning.", 150)
    )
)

sealed class BodyHomeIntent {
    data class LoadMetrics(val email: String, val plan: PlanResult? = null) : BodyHomeIntent()
    object CompleteRestDay : BodyHomeIntent()
    object HideCompletionAnimation : BodyHomeIntent()
    data class AcceptChallenge(val id: String) : BodyHomeIntent()
    data class CompleteChallenge(val id: String) : BodyHomeIntent()
    data class SwapDays(val currentPlan: PlanResult, val dayA: Int, val dayB: Int, val onResult: (PlanResult) -> Unit) : BodyHomeIntent()
    data class CompleteWorkoutSession(
        val email: String,
        val isExtraWorkout: Boolean = false,
        val totalKcal: Int = 0,
        val totalTimeMin: Double = 0.0,
        val exerciseResults: List<Map<String, Any>> = emptyList(),
        val focusAreas: List<String> = emptyList(),
        val onCompletion: (WorkoutCompletionResult?) -> Unit = {}
    ) : BodyHomeIntent()
}

data class StreakUpdateEvent(val newStreak: Int, val isRestDay: Boolean = false)

/**
 * Faza 30.2 вҖ” BodyModuleHomeViewModel brez kakrЕЎnih koli Firebase SDK klicev.
 * Faza 30.6 вҖ” Dodan BodyMeasurementsRepository za zgodovino meritev.
 *
 * Auth stanje pride reaktivno prek [AuthStateRepository] vmesnika.
 * Profil se avtomatiДҚno osveЕҫuje ob spremembi prijave (flatMapLatest).
 */
class BodyModuleHomeViewModel(
    private val getBodyMetrics: GetBodyMetricsUseCase,
    private val updateBodyMetrics: UpdateBodyMetricsUseCase,
    private val swapPlanDays: SwapPlanDaysUseCase,
    private val gamificationUseCase: ManageGamificationUseCase? = null,
    private val userProfileRepository: UserProfileRepository,
    private val authStateRepository: AuthStateRepository,
    // Faza 30.6: Repozitorij za shranjevanje in opazovanje zgodovine meritev
    private val bodyMeasurementsRepository: BodyMeasurementsRepository
) : ViewModel() {

    // в”Җв”Җ Faza 30.1 вҖ” Domain Use Case za telesni Zlati Rez в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    private val calculateBodyGoldenRatio = CalculateBodyGoldenRatioUseCase()

    // в”Җв”Җ Faza 30.6 вҖ” Use Case za shranjevanje meritev (DI prek konstruktorja) в”Җв”Җ
    private val saveMeasurementsUseCase = SaveBodyMeasurementsUseCase(bodyMeasurementsRepository)

    // в”Җв”Җ Faza 30.2 вҖ” Reaktivni profil brez Firebase v VM в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    /**
     * flatMapLatest: ob vsaki spremembi stanja prijave (login/logout) se
     * avtomatiДҚno zamenja na pravi profil ali flowOf(null).
     * PreЕҫivi rotacijo zaslona вҖ” ViewModel ostane Еҫiv med config change.
     */
    val bodyProfile: StateFlow<UserProfile?> =
        authStateRepository.observeCurrentUserEmail()
            .flatMapLatest { email ->
                if (email != null) userProfileRepository.observeUserProfile(email)
                else flowOf(null)
            }
            .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), null)

    // в”Җв”Җ Faza 30.6 вҖ” Reaktivni tok zgodovine meritev (za grafe napredka) в”Җв”Җв”Җв”Җв”Җв”Җ
    /**
     * Urejeno ASC po timestamp вҖ” pripravljeno za risanje grafov.
     * Samodejno se ugasne ob odjavi (flatMapLatest + flowOf(emptyList())).
     */
    val measurementsHistory: StateFlow<List<BodyMeasurementEntry>> =
        authStateRepository.observeCurrentUserEmail()
            .flatMapLatest { email ->
                if (email != null) bodyMeasurementsRepository.observeMeasurementsHistory()
                else flowOf(emptyList())
            }
            .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), emptyList())

    // в”Җв”Җ Faza 30.1 вҖ” Vhodni podatki za Golden Ratio (iz UI vnosa) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    /** UI kliДҚe [updateBodyMeasurements] ko uporabnik vnese obsege. */
    private val _bodyMeasurements = MutableStateFlow(BodyMeasurementsInput())

    // в”Җв”Җ Faza 30.8 вҖ” Stanje shranjevanja (interno вҖ” javno prek goldenRatioUiState) в”Җ
    private val _isSaving = MutableStateFlow(false)

    /**
     * Faza 31.1 вҖ” ENOTEN UI STATE za Golden Ratio sekcijo.
     * Faza 31.2 вҖ” IllegalArgumentException вҶ’ Success(inputErrorRes=...) namesto Error stanja.
     *
     * Kombinira 3 vire (bodyProfile + _bodyMeasurements + _isSaving) v en atomaren tok.
     * Stanje:
     *   bodyProfile == null          вҶ’ Loading  (Firestore ЕЎe ni odgovoril)
     *   bodyProfile != null          вҶ’ Success  (pokaЕҫi vnose, opcijsko result)
     *   IllegalArgumentException     вҶ’ Success(inputErrorRes=R.string.*)
     *                                  Vnosna polja ostanejo vidna in aktivna!
     *   GoldenRatioUiState.Error     вҶ’ rezervirano za prihodnje Firestore napake
     */
    val goldenRatioUiState: StateFlow<GoldenRatioUiState> = combine(
        bodyProfile,
        _bodyMeasurements,
        _isSaving
    ) { profile, measurements, saving ->
        when {
            profile == null -> GoldenRatioUiState.Loading
            else -> {
                // Poskusi izraДҚun samo ko sta obe obvezni vrednosti vneseni
                if (measurements.shoulderCm > 0.0 && measurements.waistCm > 0.0) {
                    try {
                        val result = calculateBodyGoldenRatio(
                            shoulderCm = measurements.shoulderCm,
                            waistCm    = measurements.waistCm,
                            hipCm      = measurements.hipCm,
                            heightCm   = profile.height ?: measurements.heightCm,
                            isMale     = profile.gender?.equals("Male", ignoreCase = true) ?: true
                        )
                        // UspeЕЎen izraДҚun вҶ’ Success z rezultatom, brez napake vnosa
                        GoldenRatioUiState.Success(
                            profileHeight = profile.height,
                            data          = result,
                            isSaving      = saving,
                            inputErrorRes = null
                        )
                    } catch (e: IllegalArgumentException) {
                        // Faza 31.2: vrednosti zunaj bioloЕЎkih meja (30вҖ“250 cm)
                        // вҶ’ OSTANEMO v Success, ne zamenjamo zaslona!
                        // inputErrorRes prikaЕҫe inline napako pod vnosnimi polji.
                        android.util.Log.w("BodyModuleHomeVM", "Inline input error: ${e.message}")
                        GoldenRatioUiState.Success(
                            profileHeight = profile.height,
                            data          = null,
                            isSaving      = saving,
                            inputErrorRes = R.string.error_invalid_measurements
                        )
                    }
                } else {
                    // Polja prazna ali niso vneseni вҖ” ДҚisto stanje brez napak
                    GoldenRatioUiState.Success(
                        profileHeight = profile.height,
                        data          = null,
                        isSaving      = saving,
                        inputErrorRes = null
                    )
                }
            }
        }
    }.stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), GoldenRatioUiState.Loading)

    /** KliДҚe UI ko vnese meritve (obseg ramen, pas, boki). */
    fun updateBodyMeasurements(
        shoulderCm: Double,
        waistCm: Double,
        hipCm: Double = 0.0,
        heightCm: Double = 0.0
    ) {
        _bodyMeasurements.value = BodyMeasurementsInput(shoulderCm, waistCm, hipCm, heightCm)
    }

    // в”Җв”Җ Faza 30.9 вҖ” Enkratni UI dogodki (Channel = natanko en sprejem) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    /**
     * Channel<BodyUiEvent>: poЕЎiljamo enkratne dogodke (Snackbar, navigacijaвҖҰ).
     * receiveAsFlow() v UI posluЕЎa z LaunchedEffect.
     *
     * Zakaj Channel in ne SharedFlow:
     *   SharedFlow (replay=0) bi izgubil dogodek, ДҚe UI ni ЕЎe naroДҚen.
     *   Channel.BUFFERED ohrani sporoДҚilo dokler ga UI ne prebere.
     */
    private val _uiEvent = Channel<BodyUiEvent>(Channel.BUFFERED)
    val uiEvents = _uiEvent.receiveAsFlow()

    /**
     * Faza 30.6 вҖ” Shrani meritve v Firestore (batch write):
     *   a) Posodobi profil z aktualnimi vrednostmi
     *   b) Doda vnos v measurements_history (za grafe)
     *
     * Faza 30.8 вҖ” isSaving guard: klik na gumb med shranjevanjem se v celoti ignorira.
     * Faza 30.9 вҖ” napake se poЕЎljejo kot BodyUiEvent.Error na Channel (вҶ’ Snackbar v UI).
     *
     * Klic chain: UI вҶ’ VM вҶ’ SaveBodyMeasurementsUseCase вҶ’ BodyMeasurementsRepository вҶ’ Firestore
     */
    fun saveBodyMeasurements(
        shoulderCm: Double,
        waistCm: Double,
        hipCm: Double = 0.0,
        heightCm: Double = 0.0
    ) {
        // Dvojni klik вҶ’ prezri, ДҚe shranjevanje Еҫe teДҚe
        if (_isSaving.value) return
        viewModelScope.launch {
            _isSaving.value = true
            try {
                val result = saveMeasurementsUseCase(shoulderCm, waistCm, hipCm, heightCm)
                result.onSuccess {
                    android.util.Log.d("BodyModuleHomeVM", "вң… Meritve shranjene v zgodovino")
                    _uiEvent.send(BodyUiEvent.SaveSuccess)
                }
                result.onFailure { e ->
                    android.util.Log.e("BodyModuleHomeVM", "вқҢ Napaka pri shranjevanju meritev: ${e.message}")
                    _uiEvent.send(BodyUiEvent.Error("Shranjevanje ni uspelo. Preverite povezavo."))
                }
            } finally {
                // Vedno osvobodi, tudi ob nenapovedani izjemi
                _isSaving.value = false
            }
        }
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private val _ui = MutableStateFlow(BodyHomeUiState())
    val ui: StateFlow<BodyHomeUiState> = _ui.asStateFlow()

    private val _streakUpdatedEvent = MutableSharedFlow<StreakUpdateEvent>(extraBufferCapacity = 1)
    val streakUpdatedEvent: SharedFlow<StreakUpdateEvent> = _streakUpdatedEvent.asSharedFlow()

    /**
     * Faza 23: Job tracking za LoadMetrics вҖ” vsak klic cancela prejЕЎnjega.
     * PrepreДҚuje race condition med vzporednimi Firestore branii.
     */
    private var loadMetricsJob: Job? = null

    fun handleIntent(intent: BodyHomeIntent) {
        when (intent) {
            is BodyHomeIntent.LoadMetrics -> {
                // Cancela morebitni prejЕЎnji LoadMetrics вҖ” prepreДҚi dvojno branje
                loadMetricsJob?.cancel()
                loadMetricsJob = viewModelScope.launch {
                    _ui.value = _ui.value.copy(isLoading = true, errorMessage = null)
                    try {
                        getBodyMetrics.invoke(intent.email).collect { metrics ->
                            if (metrics.isLoading) return@collect
                            val todayIsRest = intent.plan?.weeks
                                ?.flatMap { it.days }
                                ?.firstOrNull { it.dayNumber == metrics.planDay }
                                ?.isRestDay ?: false

                            _ui.value = _ui.value.copy(
                                streakDays             = metrics.streakDays,
                                streakFreezes          = metrics.streakFreezes,
                                weeklyDone             = metrics.weeklyDone,
                                weeklyTarget           = metrics.weeklyTarget,
                                planDay                = metrics.planDay,
                                totalWorkoutsCompleted = metrics.totalWorkoutsCompleted,
                                isWorkoutDoneToday     = metrics.isWorkoutDoneToday,
                                dailyKcal              = metrics.dailyKcal,
                                todayIsRest            = todayIsRest,
                                todayStatus            = metrics.todayStatus,
                                isLoading              = false,
                                errorMessage           = metrics.errorMessage
                            )
                        }
                    } catch (e: Exception) {
                        _ui.value = _ui.value.copy(errorMessage = e.message, isLoading = false)
                    }
                }
            }

            is BodyHomeIntent.CompleteRestDay -> {
                if (gamificationUseCase == null) {
                    android.util.Log.w("BodyModuleHomeVM", "gamificationUseCase ni nastavljen вҖ” preskoДҚim CompleteRestDay")
                    return
                }
                viewModelScope.launch {
                    _ui.value = _ui.value.copy(isLoading = true)
                    try {
                        val newStreak = gamificationUseCase.restDayInitiated()
                        _ui.value = _ui.value.copy(
                            isWorkoutDoneToday = true,
                            streakDays         = newStreak,
                            todayStatus        = UserDayStatus.REST_DAY_DONE,
                            isLoading          = false
                        )
                        _streakUpdatedEvent.tryEmit(StreakUpdateEvent(newStreak = newStreak, isRestDay = true))
                    } catch (e: Exception) {
                        _ui.value = _ui.value.copy(isLoading = false, errorMessage = e.message)
                    }
                }
            }

            is BodyHomeIntent.HideCompletionAnimation ->
                _ui.value = _ui.value.copy(showCompletionAnimation = false)

            is BodyHomeIntent.AcceptChallenge  -> { /* lokalni state */ }
            is BodyHomeIntent.CompleteChallenge -> { /* lokalni state */ }

            is BodyHomeIntent.SwapDays -> {
                // Faza 30.4: ViewModel kliДҚe SAMO SwapPlanDaysUseCase вҖ” ne PlanDataStore.
                // Klic chain: VM вҶ’ UseCase (validacija + lokalni model) вҶ’ Repository вҶ’ DataStore
                viewModelScope.launch {
                    _ui.value = _ui.value.copy(isLoading = true, errorMessage = null)
                    val lockedDay = if (_ui.value.isWorkoutDoneToday) _ui.value.planDay else null
                    val res = swapPlanDays.invoke(intent.currentPlan, intent.dayA, intent.dayB, lockedDay)
                    _ui.value = _ui.value.copy(isLoading = false)
                    res.onSuccess { updatedPlan ->
                        // Use case vrne posodobljeni model ЕЎele po uspeЕЎni Firestore transakciji
                        intent.onResult(updatedPlan)
                    }
                    res.onFailure { e ->
                        _ui.value = _ui.value.copy(errorMessage = e.message)
                    }
                }
            }

            is BodyHomeIntent.CompleteWorkoutSession -> {
                viewModelScope.launch {
                    _ui.value = _ui.value.copy(isLoading = true, errorMessage = null)
                    val isRestDay    = _ui.value.todayIsRest
                    val isExtra      = intent.isExtraWorkout
                    val oldPlanDay   = _ui.value.planDay
                    val oldWeeklyDone = _ui.value.weeklyDone

                    val result = updateBodyMetrics.invoke(
                        email           = intent.email,
                        totalKcal       = intent.totalKcal,
                        totalTimeMin    = intent.totalTimeMin,
                        exercisesCount  = intent.exerciseResults.size,
                        planDay         = oldPlanDay,
                        isExtra         = isExtra,
                        exerciseResults = intent.exerciseResults,
                        focusAreas      = intent.focusAreas,
                        isRestDay       = isRestDay
                    )

                    result.onSuccess { completionResult ->
                        // Faza 23: OptimistiДҚni update iz WorkoutCompletionResult вҖ” brez dodatnega Firestore read-a.
                        // moveToNextDay() je atomarno Еҫe zapisal vse podatke; streak + planDay sta znana.
                        val todayStatus = when {
                            isRestDay && isExtra -> UserDayStatus.REST_WORKOUT_DONE
                            else                 -> UserDayStatus.WORKOUT_DONE
                        }
                        val newStreak   = completionResult?.newStreakDays?.takeIf { it > 0 }
                            ?: (_ui.value.streakDays + if (todayStatus.contributesToStreak) 1 else 0)
                        val newPlanDay  = completionResult?.newPlanDay?.takeIf { it > 0 }
                            ?: (oldPlanDay + if (!isExtra) 1 else 0)
                        val newWeekly   = if (todayStatus != UserDayStatus.REST_WORKOUT_DONE)
                            (oldWeeklyDone + 1).coerceAtMost(_ui.value.weeklyTarget)
                        else oldWeeklyDone

                        _ui.value = _ui.value.copy(
                            streakDays              = newStreak,
                            weeklyDone              = newWeekly,
                            planDay                 = newPlanDay,
                            isWorkoutDoneToday      = true,
                            todayStatus             = todayStatus,
                            showCompletionAnimation = !isExtra,
                            isLoading               = false
                        )
                        _streakUpdatedEvent.tryEmit(StreakUpdateEvent(newStreak = newStreak))
                        intent.onCompletion(completionResult)
                    }
                    result.onFailure { error ->
                        _ui.value = _ui.value.copy(isLoading = false, errorMessage = error.message)
                        intent.onCompletion(null)
                    }
                }
            }
        }
    }
}

package com.example.myapplication.viewmodels

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.myapplication.R
import com.example.myapplication.data.UserProfile
import com.example.myapplication.domain.model.BodyField
import com.example.myapplication.domain.model.BodyGoldenRatioResult
import com.example.myapplication.domain.model.PlanResult
import com.example.myapplication.domain.model.UserDayStatus
import com.example.myapplication.domain.gamification.ManageGamificationUseCase
import com.example.myapplication.domain.gamification.WorkoutCompletionResult
import com.example.myapplication.domain.auth.AuthStateRepository
import com.example.myapplication.domain.profile.UserProfileRepository
import com.example.myapplication.domain.model.BodyMeasurementEntry
import com.example.myapplication.domain.repository.BodyMeasurementsRepository
import com.example.myapplication.domain.usecase.CalculateBodyGoldenRatioUseCase
import com.example.myapplication.domain.usecase.GetBodyMetricsUseCase
import com.example.myapplication.domain.usecase.SaveBodyMeasurementsUseCase
import com.example.myapplication.domain.usecase.SwapPlanDaysUseCase
import com.example.myapplication.domain.usecase.UpdateBodyMetricsUseCase
import kotlinx.coroutines.Job
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharedFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asSharedFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.flatMapLatest
import kotlinx.coroutines.flow.flowOf
import kotlinx.coroutines.flow.receiveAsFlow
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch

/**
 * Faza 30.9 вҖ” Enkratni UI dogodki za BodyModul.
 *
 * Razlika od StateFlow:
 *   StateFlow  = trajno stanje (kateri zaslon je odprt, ali nalagamoвҖҰ)
 *   Channel    = enkratni dogodek (prikaЕҫi Snackbar, navigiraj, zapri dialog)
 *
 * Ne smeЕЎ shranjevati teh vrednosti v StateFlow вҖ” Snackbar bi se ob rotaciji zaslona
 * prikazal znova. Channel zagotavlja natanko en sprejem.
 */
sealed interface BodyUiEvent {
    /** Meritve so bile uspeЕЎno shranjene v Firestore. */
    data object SaveSuccess : BodyUiEvent
    /** Napaka med shranjevanjem вҖ” prikaЕҫi Snackbar z [message]. */
    data class Error(val message: String) : BodyUiEvent
}

/**
 * Faza 31.1 вҖ” Enoten UI state za Golden Ratio sekcijo.
 *
 * NadomeЕЎДҚa tri razprЕЎene StateFlow-e:
 *   bodyProfile: StateFlow<UserProfile?>     вҶ’ pokrit z Loading/Success
 *   goldenRatioResults: StateFlow<Result?>   вҶ’ Success.data
 *   isSaving: StateFlow<Boolean>             вҶ’ Success.isSaving
 *
 * Prednosti:
 *   вҖў Atomarni prehodi вҖ” UI nikoli ne vidi nedosledne kombinacije vrednosti
 *   вҖў Error.messageRes je Int (R.string.*) вҶ’ brez hardkodiranih nizov v VM
 *   вҖў Loading stanje prepreДҚuje vizualno utripanje ("flash of empty content")
 */
sealed interface GoldenRatioUiState {
    /** Profil se nalaga iz Firestore вҖ” pokaЕҫi CircularProgressIndicator. */
    data object Loading : GoldenRatioUiState

    /**
     * Profil naloЕҫen вҖ” pokaЕҫi celotni vmesnik z vnosi.
     * @param profileHeight  ViЕЎina iz profila (za prikaz in izraДҚun pas/viЕЎina razmerja)
     * @param data           Rezultat izraДҚuna; null dokler uporabnik ne vnese meritev
     * @param isSaving       true med Firestore batch write вҖ” gumb onemogoДҚen
     * @param inputErrorRes  Faza 31.2 вҖ” R.string.* ID inline validacijske napake vnosa;
     *                       null = vnos je veljaven ali prazen.
     *                       PrikaЕҫe se pod vnosnimi polji, ne zamenja celotnega zaslona.
     */
    data class Success(
        val profileHeight: Double?,
        val data: BodyGoldenRatioResult?,
        val isSaving: Boolean = false,
        val inputErrorRes: Int? = null
    ) : GoldenRatioUiState

    /**
     * Napaka pri inicializaciji zaslona (npr. izpad Firestore med nalaganjem profila).
     * NI namenjen validacijskim napakam vnosa вҖ” za to se uporablja [Success.inputErrorRes].
     * @param messageRes  ID string resursa (R.string.*) вҖ” lokalizabilen, brez Context v VM
     */
    data class Error(val messageRes: Int) : GoldenRatioUiState
}

/**
 * Faza 30.1 вҖ” Vhodni podatki za telesni Zlati Rez.
 * shoulderCm/waistCm = 0.0 pomeni: ni vnosa вҶ’ goldenRatioResults = null.
 */
data class BodyMeasurementsInput(
    val shoulderCm: Double = 0.0,
    val waistCm: Double    = 0.0,
    val hipCm: Double      = 0.0,
    val heightCm: Double   = 0.0  // fallback, ДҚe profil nima viЕЎine
)

data class Challenge(
    val id: String,
    val title: String,
    val description: String,
    val xpReward: Int = 100,
    val accepted: Boolean = false,
    val completed: Boolean = false,
    val iconRes: Int? = null
)

/**
 * UI stanje za Body Home zaslon.
 *
 * Faza 21: todayStatus je zdaj tipsko-varni [UserDayStatus] namesto String.
 */
data class BodyHomeUiState(
    val streakDays: Int = 0,
    val streakFreezes: Int = 0,
    val weeklyDone: Int = 0,
    val weeklyTarget: Int = 3,
    val planDay: Int = 1,
    val totalWorkoutsCompleted: Int = 0,
    val workoutsToday: Int = 0,
    val isWorkoutDoneToday: Boolean = false,
    val dailyKcal: Int = 0,
    val showCompletionAnimation: Boolean = false,
    val todayIsRest: Boolean = false,
    val outdoorSuggestion: String? = null,
    val errorMessage: String? = null,
    val isLoading: Boolean = false,
    /** Tipsko-varni status danaЕЎnjega dne вҖ” nadomeЕЎДҚa String "WORKOUT_DONE" itd. */
    val todayStatus: UserDayStatus = UserDayStatus.WORKOUT_PENDING,
    val challenges: List<Challenge> = listOf(
        Challenge("c1", "30 days sixpack", "Get a sixpack in 30 days. Perform core exercises daily.", 500),
        Challenge("c2", "30 days pushups", "Improve your pushups in 30 days. Do 50 pushups/day.", 300),
        Challenge("c3", "Mobility week", "Increase your ROM in 7 days. Stretch every morning.", 150)
    )
)

sealed class BodyHomeIntent {
    data class LoadMetrics(val email: String, val plan: PlanResult? = null) : BodyHomeIntent()
    object CompleteRestDay : BodyHomeIntent()
    object HideCompletionAnimation : BodyHomeIntent()
    data class AcceptChallenge(val id: String) : BodyHomeIntent()
    data class CompleteChallenge(val id: String) : BodyHomeIntent()
    data class SwapDays(val currentPlan: PlanResult, val dayA: Int, val dayB: Int, val onResult: (PlanResult) -> Unit) : BodyHomeIntent()
    data class CompleteWorkoutSession(
        val email: String,
        val isExtraWorkout: Boolean = false,
        val totalKcal: Int = 0,
        val totalTimeMin: Double = 0.0,
        val exerciseResults: List<Map<String, Any>> = emptyList(),
        val focusAreas: List<String> = emptyList(),
        val onCompletion: (WorkoutCompletionResult?) -> Unit = {}
    ) : BodyHomeIntent()
}

data class StreakUpdateEvent(val newStreak: Int, val isRestDay: Boolean = false)

/**
 * Faza 30.2 вҖ” BodyModuleHomeViewModel brez kakrЕЎnih koli Firebase SDK klicev.
 * Faza 30.6 вҖ” Dodan BodyMeasurementsRepository za zgodovino meritev.
 *
 * Auth stanje pride reaktivno prek [AuthStateRepository] vmesnika.
 * Profil se avtomatiДҚno osveЕҫuje ob spremembi prijave (flatMapLatest).
 */
class BodyModuleHomeViewModel(
    private val getBodyMetrics: GetBodyMetricsUseCase,
    private val updateBodyMetrics: UpdateBodyMetricsUseCase,
    private val swapPlanDays: SwapPlanDaysUseCase,
    private val gamificationUseCase: ManageGamificationUseCase? = null,
    private val userProfileRepository: UserProfileRepository,
    private val authStateRepository: AuthStateRepository,
    // Faza 30.6: Repozitorij za shranjevanje in opazovanje zgodovine meritev
    private val bodyMeasurementsRepository: BodyMeasurementsRepository
) : ViewModel() {

    // в”Җв”Җ Faza 30.1 вҖ” Domain Use Case za telesni Zlati Rez в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    private val calculateBodyGoldenRatio = CalculateBodyGoldenRatioUseCase()

    // в”Җв”Җ Faza 30.6 вҖ” Use Case za shranjevanje meritev (DI prek konstruktorja) в”Җв”Җ
    private val saveMeasurementsUseCase = SaveBodyMeasurementsUseCase(bodyMeasurementsRepository)

    // в”Җв”Җ Faza 30.2 вҖ” Reaktivni profil brez Firebase v VM в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    /**
     * flatMapLatest: ob vsaki spremembi stanja prijave (login/logout) se
     * avtomatiДҚno zamenja na pravi profil ali flowOf(null).
     * PreЕҫivi rotacijo zaslona вҖ” ViewModel ostane Еҫiv med config change.
     */
    val bodyProfile: StateFlow<UserProfile?> =
        authStateRepository.observeCurrentUserEmail()
            .flatMapLatest { email ->
                if (email != null) userProfileRepository.observeUserProfile(email)
                else flowOf(null)
            }
            .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), null)

    // в”Җв”Җ Faza 30.6 вҖ” Reaktivni tok zgodovine meritev (za grafe napredka) в”Җв”Җв”Җв”Җв”Җв”Җ
    /**
     * Urejeno ASC po timestamp вҖ” pripravljeno za risanje grafov.
     * Samodejno se ugasne ob odjavi (flatMapLatest + flowOf(emptyList())).
     */
    val measurementsHistory: StateFlow<List<BodyMeasurementEntry>> =
        authStateRepository.observeCurrentUserEmail()
            .flatMapLatest { email ->
                if (email != null) bodyMeasurementsRepository.observeMeasurementsHistory()
                else flowOf(emptyList())
            }
            .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), emptyList())

    // в”Җв”Җ Faza 30.1 вҖ” Vhodni podatki za Golden Ratio (iz UI vnosa) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    /** UI kliДҚe [updateBodyMeasurements] ko uporabnik vnese obsege. */
    private val _bodyMeasurements = MutableStateFlow(BodyMeasurementsInput())

    // в”Җв”Җ Faza 30.8 вҖ” Stanje shranjevanja (interno вҖ” javno prek goldenRatioUiState) в”Җ
    private val _isSaving = MutableStateFlow(false)

    /**
     * Faza 31.1 вҖ” ENOTEN UI STATE za Golden Ratio sekcijo.
     * Faza 31.2 вҖ” IllegalArgumentException вҶ’ Success(inputErrorRes=...) namesto Error stanja.
     *
     * Kombinira 3 vire (bodyProfile + _bodyMeasurements + _isSaving) v en atomaren tok.
     * Stanje:
     *   bodyProfile == null          вҶ’ Loading  (Firestore ЕЎe ni odgovoril)
     *   bodyProfile != null          вҶ’ Success  (pokaЕҫi vnose, opcijsko result)
     *   IllegalArgumentException     вҶ’ Success(inputErrorRes=R.string.*)
     *                                  Vnosna polja ostanejo vidna in aktivna!
     *   GoldenRatioUiState.Error     вҶ’ rezervirano za prihodnje Firestore napake
     */
    val goldenRatioUiState: StateFlow<GoldenRatioUiState> = combine(
        bodyProfile,
        _bodyMeasurements,
        _isSaving
    ) { profile, measurements, saving ->
        when {
            profile == null -> GoldenRatioUiState.Loading
            else -> {
                // Poskusi izraДҚun samo ko sta obe obvezni vrednosti vneseni
                if (measurements.shoulderCm > 0.0 && measurements.waistCm > 0.0) {
                    try {
                        val result = calculateBodyGoldenRatio(
                            shoulderCm = measurements.shoulderCm,
                            waistCm    = measurements.waistCm,
                            hipCm      = measurements.hipCm,
                            heightCm   = profile.height ?: measurements.heightCm,
                            isMale     = profile.gender?.equals("Male", ignoreCase = true) ?: true
                        )
                        // UspeЕЎen izraДҚun вҶ’ Success z rezultatom, brez napake vnosa
                        GoldenRatioUiState.Success(
                            profileHeight = profile.height,
                            data          = result,
                            isSaving      = saving,
                            inputErrorRes = null
                        )
                    } catch (e: IllegalArgumentException) {
                        // Faza 31.2: vrednosti zunaj bioloЕЎkih meja (30вҖ“250 cm)
                        // вҶ’ OSTANEMO v Success, ne zamenjamo zaslona!
                        // inputErrorRes prikaЕҫe inline napako pod vnosnimi polji.
                        android.util.Log.w("BodyModuleHomeVM", "Inline input error: ${e.message}")
                        GoldenRatioUiState.Success(
                            profileHeight = profile.height,
                            data          = null,
                            isSaving      = saving,
                            inputErrorRes = R.string.error_invalid_measurements
                        )
                    }
                } else {
                    // Polja prazna ali niso vneseni вҖ” ДҚisto stanje brez napak
                    GoldenRatioUiState.Success(
                        profileHeight = profile.height,
                        data          = null,
                        isSaving      = saving,
                        inputErrorRes = null
                    )
                }
            }
        }
    }.stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), GoldenRatioUiState.Loading)

    /** KliДҚe UI ko vnese meritve (obseg ramen, pas, boki). */
    fun updateBodyMeasurements(
        shoulderCm: Double,
        waistCm: Double,
        hipCm: Double = 0.0,
        heightCm: Double = 0.0
    ) {
        _bodyMeasurements.value = BodyMeasurementsInput(shoulderCm, waistCm, hipCm, heightCm)
    }

    // в”Җв”Җ Faza 30.9 вҖ” Enkratni UI dogodki (Channel = natanko en sprejem) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    /**
     * Channel<BodyUiEvent>: poЕЎiljamo enkratne dogodke (Snackbar, navigacijaвҖҰ).
     * receiveAsFlow() v UI posluЕЎa z LaunchedEffect.
     *
     * Zakaj Channel in ne SharedFlow:
     *   SharedFlow (replay=0) bi izgubil dogodek, ДҚe UI ni ЕЎe naroДҚen.
     *   Channel.BUFFERED ohrani sporoДҚilo dokler ga UI ne prebere.
     */
    private val _uiEvent = Channel<BodyUiEvent>(Channel.BUFFERED)
    val uiEvents = _uiEvent.receiveAsFlow()

    /**
     * Faza 30.6 вҖ” Shrani meritve v Firestore (batch write):
     *   a) Posodobi profil z aktualnimi vrednostmi
     *   b) Doda vnos v measurements_history (za grafe)
     *
     * Faza 30.8 вҖ” isSaving guard: klik na gumb med shranjevanjem se v celoti ignorira.
     * Faza 30.9 вҖ” napake se poЕЎljejo kot BodyUiEvent.Error na Channel (вҶ’ Snackbar v UI).
     *
     * Klic chain: UI вҶ’ VM вҶ’ SaveBodyMeasurementsUseCase вҶ’ BodyMeasurementsRepository вҶ’ Firestore
     */
    fun saveBodyMeasurements(
        shoulderCm: Double,
        waistCm: Double,
        hipCm: Double = 0.0,
        heightCm: Double = 0.0
    ) {
        // Dvojni klik вҶ’ prezri, ДҚe shranjevanje Еҫe teДҚe
        if (_isSaving.value) return
        viewModelScope.launch {
            _isSaving.value = true
            try {
                val result = saveMeasurementsUseCase(shoulderCm, waistCm, hipCm, heightCm)
                result.onSuccess {
                    android.util.Log.d("BodyModuleHomeVM", "вң… Meritve shranjene v zgodovino")
                    _uiEvent.send(BodyUiEvent.SaveSuccess)
                }
                result.onFailure { e ->
                    android.util.Log.e("BodyModuleHomeVM", "вқҢ Napaka pri shranjevanju meritev: ${e.message}")
                    _uiEvent.send(BodyUiEvent.Error("Shranjevanje ni uspelo. Preverite povezavo."))
                }
            } finally {
                // Vedno osvobodi, tudi ob nenapovedani izjemi
                _isSaving.value = false
            }
        }
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    private val _ui = MutableStateFlow(BodyHomeUiState())
    val ui: StateFlow<BodyHomeUiState> = _ui.asStateFlow()

    private val _streakUpdatedEvent = MutableSharedFlow<StreakUpdateEvent>(extraBufferCapacity = 1)
    val streakUpdatedEvent: SharedFlow<StreakUpdateEvent> = _streakUpdatedEvent.asSharedFlow()

    /**
     * Faza 23: Job tracking za LoadMetrics вҖ” vsak klic cancela prejЕЎnjega.
     * PrepreДҚuje race condition med vzporednimi Firestore branii.
     */
    private var loadMetricsJob: Job? = null

    fun handleIntent(intent: BodyHomeIntent) {
        when (intent) {
            is BodyHomeIntent.LoadMetrics -> {
                // Cancela morebitni prejЕЎnji LoadMetrics вҖ” prepreДҚi dvojno branje
                loadMetricsJob?.cancel()
                loadMetricsJob = viewModelScope.launch {
                    _ui.value = _ui.value.copy(isLoading = true, errorMessage = null)
                    try {
                        getBodyMetrics.invoke(intent.email).collect { metrics ->
                            if (metrics.isLoading) return@collect
                            val todayIsRest = intent.plan?.weeks
                                ?.flatMap { it.days }
                                ?.firstOrNull { it.dayNumber == metrics.planDay }
                                ?.isRestDay ?: false

                            _ui.value = _ui.value.copy(
                                streakDays             = metrics.streakDays,
                                streakFreezes          = metrics.streakFreezes,
                                weeklyDone             = metrics.weeklyDone,
                                weeklyTarget           = metrics.weeklyTarget,
                                planDay                = metrics.planDay,
                                totalWorkoutsCompleted = metrics.totalWorkoutsCompleted,
                                isWorkoutDoneToday     = metrics.isWorkoutDoneToday,
                                dailyKcal              = metrics.dailyKcal,
                                todayIsRest            = todayIsRest,
                                todayStatus            = metrics.todayStatus,
                                isLoading              = false,
                                errorMessage           = metrics.errorMessage
                            )
                        }
                    } catch (e: Exception) {
                        _ui.value = _ui.value.copy(errorMessage = e.message, isLoading = false)
                    }
                }
            }

            is BodyHomeIntent.CompleteRestDay -> {
                if (gamificationUseCase == null) {
                    android.util.Log.w("BodyModuleHomeVM", "gamificationUseCase ni nastavljen вҖ” preskoДҚim CompleteRestDay")
                    return
                }
                viewModelScope.launch {
                    _ui.value = _ui.value.copy(isLoading = true)
                    try {
                        val newStreak = gamificationUseCase.restDayInitiated()
                        _ui.value = _ui.value.copy(
                            isWorkoutDoneToday = true,
                            streakDays         = newStreak,
                            todayStatus        = UserDayStatus.REST_DAY_DONE,
                            isLoading          = false
                        )
                        _streakUpdatedEvent.tryEmit(StreakUpdateEvent(newStreak = newStreak, isRestDay = true))
                    } catch (e: Exception) {
                        _ui.value = _ui.value.copy(isLoading = false, errorMessage = e.message)
                    }
                }
            }

            is BodyHomeIntent.HideCompletionAnimation ->
                _ui.value = _ui.value.copy(showCompletionAnimation = false)

            is BodyHomeIntent.AcceptChallenge  -> { /* lokalni state */ }
            is BodyHomeIntent.CompleteChallenge -> { /* lokalni state */ }

            is BodyHomeIntent.SwapDays -> {
                // Faza 30.4: ViewModel kliДҚe SAMO SwapPlanDaysUseCase вҖ” ne PlanDataStore.
                // Klic chain: VM вҶ’ UseCase (validacija + lokalni model) вҶ’ Repository вҶ’ DataStore
                viewModelScope.launch {
                    _ui.value = _ui.value.copy(isLoading = true, errorMessage = null)
                    val lockedDay = if (_ui.value.isWorkoutDoneToday) _ui.value.planDay else null
                    val res = swapPlanDays.invoke(intent.currentPlan, intent.dayA, intent.dayB, lockedDay)
                    _ui.value = _ui.value.copy(isLoading = false)
                    res.onSuccess { updatedPlan ->
                        // Use case vrne posodobljeni model ЕЎele po uspeЕЎni Firestore transakciji
                        intent.onResult(updatedPlan)
                    }
                    res.onFailure { e ->
                        _ui.value = _ui.value.copy(errorMessage = e.message)
                    }
                }
            }

            is BodyHomeIntent.CompleteWorkoutSession -> {
                viewModelScope.launch {
                    _ui.value = _ui.value.copy(isLoading = true, errorMessage = null)
                    val isRestDay    = _ui.value.todayIsRest
                    val isExtra      = intent.isExtraWorkout
                    val oldPlanDay   = _ui.value.planDay
                    val oldWeeklyDone = _ui.value.weeklyDone

                    val result = updateBodyMetrics.invoke(
                        email           = intent.email,
                        totalKcal       = intent.totalKcal,
                        totalTimeMin    = intent.totalTimeMin,
                        exercisesCount  = intent.exerciseResults.size,
                        planDay         = oldPlanDay,
                        isExtra         = isExtra,
                        exerciseResults = intent.exerciseResults,
                        focusAreas      = intent.focusAreas,
                        isRestDay       = isRestDay
                    )

                    result.onSuccess { completionResult ->
                        // Faza 23: OptimistiДҚni update iz WorkoutCompletionResult вҖ” brez dodatnega Firestore read-a.
                        // moveToNextDay() je atomarno Еҫe zapisal vse podatke; streak + planDay sta znana.
                        val todayStatus = when {
                            isRestDay && isExtra -> UserDayStatus.REST_WORKOUT_DONE
                            else                 -> UserDayStatus.WORKOUT_DONE
                        }
                        val newStreak   = completionResult?.newStreakDays?.takeIf { it > 0 }
                            ?: (_ui.value.streakDays + if (todayStatus.contributesToStreak) 1 else 0)
                        val newPlanDay  = completionResult?.newPlanDay?.takeIf { it > 0 }
                            ?: (oldPlanDay + if (!isExtra) 1 else 0)
                        val newWeekly   = if (todayStatus != UserDayStatus.REST_WORKOUT_DONE)
                            (oldWeeklyDone + 1).coerceAtMost(_ui.value.weeklyTarget)
                        else oldWeeklyDone

                        _ui.value = _ui.value.copy(
                            streakDays              = newStreak,
                            weeklyDone              = newWeekly,
                            planDay                 = newPlanDay,
                            isWorkoutDoneToday      = true,
                            todayStatus             = todayStatus,
                            showCompletionAnimation = !isExtra,
                            isLoading               = false
                        )
                        _streakUpdatedEvent.tryEmit(StreakUpdateEvent(newStreak = newStreak))
                        intent.onCompletion(completionResult)
                    }
                    result.onFailure { error ->
                        _ui.value = _ui.value.copy(isLoading = false, errorMessage = error.message)
                        intent.onCompletion(null)
                    }
                }
            }
        }
    }
}

package com.example.myapplication.data.gamification

import android.util.Log
import com.example.myapplication.data.UserProfile
import com.example.myapplication.domain.gamification.GamificationRepository
import com.example.myapplication.domain.gamification.GamificationState
import com.example.myapplication.domain.model.UserDayStatus
import com.example.myapplication.data.store.FirestoreHelper
import com.google.firebase.firestore.SetOptions
import kotlinx.coroutines.tasks.await
import kotlinx.datetime.Clock
import kotlinx.datetime.DateTimeUnit
import kotlinx.datetime.TimeZone
import kotlinx.datetime.minus
import kotlinx.datetime.toLocalDateTime

/**
 * Zlata koda - KMP ready Firestore implementacija za Gamification.
 * NIMA NITI ENE SharedPreferences ODVISNOSTI.
 *
 * Faza 21: Unified moveToNextDay() nadomeЕЎДҚa processActivityCompletion() + updateStreak().
 * - Ena atomarna Firestore transakcija za VSE poti aktivnostnega zakljuДҚka
 * - getYesterdayStr() DST-safe kotlinx.datetime algebra
 * - UserDayStatus tipsko-varni enum nadomeЕЎДҚa raztresene String konstante
 */
class FirestoreGamificationRepository : GamificationRepository {

    private val db get() = FirestoreHelper.getDb()

    private fun getTodayStr(): String =
        Clock.System.now().toLocalDateTime(TimeZone.currentSystemDefault()).date.toString()

    /** DST-safe izraДҚun vДҚerajЕЎnjega datuma prek kotlinx.datetime algebre. */
    private fun getYesterdayStr(): String =
        Clock.System.now()
            .toLocalDateTime(TimeZone.currentSystemDefault())
            .date.minus(1, DateTimeUnit.DAY).toString()

    private fun getTodayEpoch(): Long =
        Clock.System.now()
            .toLocalDateTime(TimeZone.currentSystemDefault())
            .date.toEpochDays().toLong()

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    // awardXP вҖ” za neodvisne klice (login, plan, itd.)
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    override suspend fun awardXP(amount: Int, reason: String) {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return
        try {
            db.runTransaction { transaction ->
                val snapshot  = transaction.get(userRef)
                val currentXp = snapshot.getLong("xp")?.toInt() ?: 0
                val newXp     = currentXp + amount
                val newLevel  = UserProfile.calculateLevel(newXp)
                transaction.set(userRef, mapOf("xp" to newXp, "level" to newLevel), SetOptions.merge())
                val logRef = userRef.collection("xp_history").document()
                transaction.set(logRef, mapOf(
                    "amount" to amount, "reason" to reason, "date" to getTodayStr(),
                    "timestamp" to Clock.System.now().toEpochMilliseconds(),
                    "xpAfter" to newXp, "levelAfter" to newLevel
                ))
            }.await()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "Napaka pri beleЕҫenju XP-ja", e)
        }
    }

    override suspend fun getCurrentStreak(): Int {
        // Faza 34 вҖ” HIGH-01 Fix: Propagiraj izjemo navzgor namesto tihega 0.
        // PrejЕЎnji catch { 0 } je ob mreЕҫni napaki vrnil streak=0, kar je UI potencialno
        // resetiral streak na niДҚlo brez dejanske spremembe v Firestoreu.
        val userRef = FirestoreHelper.getCurrentUserDocRef()
            ?: throw IllegalStateException("Uporabnik ni prijavljen вҖ” getCurrentStreak zahteva veljavno sejo.")
        return userRef.get().await().getLong("streak_days")?.toInt() ?: 0
    }

    override suspend fun markRestDayPending() {
        val userRef  = FirestoreHelper.getCurrentUserDocRef() ?: return
        val todayStr = getTodayStr()
        try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)
                @Suppress("UNCHECKED_CAST")
                val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()
                val existing = UserDayStatus.fromFirestore(dailyHistory[todayStr]?.toString())
                // Idempotentno вҖ” ne prepiЕЎi zakljuДҚenih statusov
                if (existing.isDoneToday) return@runTransaction null
                transaction.update(userRef, mapOf(
                    "dailyHistory.$todayStr" to UserDayStatus.REST_DAY_PENDING.firestoreValue
                ))
                null
            }.await()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "Napaka pri markRestDayPending()", e)
        }
    }

    override suspend fun getTodayStatus(): UserDayStatus {
        // Faza 34 вҖ” HIGH-02 Fix: Propagiraj izjemo namesto tihega WORKOUT_PENDING fallback-a.
        // Tihi fallback je bil nevaren: auth/mreЕҫna napaka bi sistema pustila misliti,
        // da vadba danes ni bila opravljena, kar bi dovolilo duplikatni zapis streaka.
        val userRef = FirestoreHelper.getCurrentUserDocRef()
            ?: throw IllegalStateException("Uporabnik ni prijavljen вҖ” getTodayStatus zahteva veljavno sejo.")
        val snapshot = userRef.get().await()
        @Suppress("UNCHECKED_CAST")
        val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()
        return UserDayStatus.fromFirestore(dailyHistory[getTodayStr()]?.toString())
    }

    override suspend fun consumeStreakFreeze(): Boolean {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return false
        return try {
            var consumed = false
            db.runTransaction { transaction ->
                val snap = transaction.get(userRef)
                val curr = snap.getLong("streak_freezes")?.toInt() ?: 0
                if (curr > 0) { transaction.update(userRef, "streak_freezes", curr - 1); consumed = true }
            }.await()
            consumed
        } catch (e: Exception) { false }
    }

    override suspend fun logBurnedCalories(todayStr: String, calories: Double) {
        try {
            val userRef     = FirestoreHelper.getCurrentUserDocRef() ?: return
            val dailyLogRef = db.collection("dailyLogs").document(todayStr)
            db.runTransaction { transaction ->
                val snap     = transaction.get(dailyLogRef)
                val existing = (snap.get("burnedCalories") as? Number)?.toDouble() ?: 0.0
                transaction.set(
                    dailyLogRef,
                    mapOf("burnedCalories" to existing + calories, "userId" to userRef.id),
                    SetOptions.merge()
                )
                null
            }.await()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "logBurnedCalories failed: ${e.message}")
        }
    }

    override suspend fun getGamificationState(): GamificationState {
        return try {
            val userRef  = FirestoreHelper.getCurrentUserDocRef() ?: return GamificationState()
            val snapshot = userRef.get().await()
            val weeklyTarget   = snapshot.getLong("weekly_target")?.toInt() ?: 0
            val workoutDone    = getTodayStatus().isDoneToday
            GamificationState(weeklyTarget = weeklyTarget, workoutDoneToday = workoutDone)
        } catch (e: Exception) { GamificationState() }
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    // moveToNextDay вҖ” SSOT za VSE aktivnostne zakljuДҚke (Faza 21)
    //
    // ENA atomarna Firestore transakcija za:
    //   в‘  De-duplikacija (ne prepiЕЎe WORKOUT_DONE z niЕҫjo prioriteto)
    //   в‘Ў Streak izraДҚun (epoch-based, Streak Freeze podpora)
    //   в‘ў plan_day +1 (samo kadar incrementPlanDay=true)
    //   в‘Ј XP + Level atomarno
    //   в‘Ө dailyHistory vpis z UserDayStatus.firestoreValue
    //   в‘Ҙ burnedCalories v dailyLogs (Nutrition bridge)
    //
    // ДҢe transakcija SPODLETI вҶ’ Room ni posodobljena (callerji prejmejo 0).
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    override suspend fun moveToNextDay(
        newStatus: UserDayStatus,
        xpToBeAwarded: Int,
        xpReason: String,
        caloriesBurned: Double,
        incrementPlanDay: Boolean
    ): Int {
        // Samo zakljuДҚitveni statusi so dovoljeni
        require(newStatus.isDoneToday) {
            "moveToNextDay zahteva zakljuДҚitveni status (WORKOUT_DONE, REST_DAY_DONE, REST_WORKOUT_DONE)."
        }

        val userRef    = FirestoreHelper.getCurrentUserDocRef() ?: return 0
        val todayStr   = getTodayStr()
        val todayEpoch = getTodayEpoch()
        val nowMillis  = Clock.System.now().toEpochMilliseconds()
        var resultStreak = 0

        return try {
            db.runTransaction { transaction ->
                // в”Җв”Җ READ faza в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                val snapshot = transaction.get(userRef)

                @Suppress("UNCHECKED_CAST")
                val dailyHistory   = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()
                val existingStatus = UserDayStatus.fromFirestore(dailyHistory[todayStr]?.toString())

                // De-dup: WORKOUT_DONE je najviЕЎja prioriteta, ne prepiЕЎi ga
                if (existingStatus == UserDayStatus.WORKOUT_DONE || existingStatus == newStatus) {
                    Log.d("GamificationRepo", "moveToNextDay: $todayStr Еҫe '$existingStatus' вҖ” de-dup preskoДҚek.")
                    resultStreak = snapshot.getLong("streak_days")?.toInt() ?: 0
                    return@runTransaction null
                }

                val oldStreak     = (snapshot.getLong("streak_days")         ?: 0L).toInt()
                val oldLastEpoch  =  snapshot.getLong("last_activity_epoch") ?: 0L
                val oldPlanDay    = (snapshot.getLong("plan_day")            ?: 1L).toInt()
                val oldFreezes    = (snapshot.getLong("streak_freezes")      ?: 0L).toInt()
                val currentXp     = (snapshot.getLong("xp")                  ?: 0L).toInt()

                // Burned calories za Nutrition bridge
                val dailyLogRef = db.collection("dailyLogs").document(todayStr)
                val logSnapshot = if (caloriesBurned > 0.0) transaction.get(dailyLogRef) else null
                val existingCals = (logSnapshot?.get("burnedCalories") as? Number)?.toDouble() ?: 0.0

                // в”Җв”Җ Streak izraДҚun в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                val dayDiff    = todayEpoch - oldLastEpoch
                var newFreezes = oldFreezes
                val newStreak: Int = when {
                    !newStatus.contributesToStreak -> oldStreak          // REST_WORKOUT_DONE = ohrani
                    oldLastEpoch == 0L             -> 1                  // Prva aktivnost kdajkoli
                    dayDiff == 0L                  -> oldStreak          // Isti dan (de-dup zgoraj bi ujel)
                    dayDiff == 1L                  -> oldStreak + 1      // VДҚeraj aktiven вҶ’ podaljЕЎaj
                    oldFreezes > 0                 -> {                  // Vrzel > 1 dan вҶ’ preveri Freeze
                        newFreezes = oldFreezes - 1
                        Log.d("GamificationRepo", "вқ„пёҸ moveToNextDay: Streak Freeze porabljen! Ostalo: $newFreezes")
                        oldStreak
                    }
                    else -> 1                                            // Ni freeze вҶ’ ponastavi na 1
                }
                resultStreak = newStreak

                // в”Җв”Җ Plan day napredovanje в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                val newPlanDay = if (incrementPlanDay) oldPlanDay + 1 else oldPlanDay

                // в”Җв”Җ XP + Level в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                val newXp    = currentXp + xpToBeAwarded
                val newLevel = UserProfile.calculateLevel(newXp)

                // в”Җв”Җ WRITE faza в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                val userUpdates = mutableMapOf<String, Any>(
                    "streak_days"             to newStreak,
                    "plan_day"                to newPlanDay,
                    "last_activity_epoch"     to todayEpoch,
                    "last_streak_update_date" to todayStr,
                    "dailyHistory.$todayStr"  to newStatus.firestoreValue,
                    "xp"                      to newXp,
                    "level"                   to newLevel
                )
                if (newFreezes != oldFreezes) userUpdates["streak_freezes"] = newFreezes
                transaction.update(userRef, userUpdates)

                // XP history log
                if (xpToBeAwarded > 0) {
                    val xpLogRef = userRef.collection("xp_history").document()
                    transaction.set(xpLogRef, mapOf(
                        "amount" to xpToBeAwarded, "reason" to xpReason,
                        "date" to todayStr, "timestamp" to nowMillis,
                        "xpAfter" to newXp, "levelAfter" to newLevel
                    ))
                }

                // Burned calories вҶ’ Nutrition bridge
                if (caloriesBurned > 0.0 && logSnapshot != null) {
                    transaction.set(
                        dailyLogRef,
                        mapOf("burnedCalories" to existingCals + caloriesBurned, "userId" to userRef.id),
                        SetOptions.merge()
                    )
                }

                Log.d("GamificationRepo",
                    "вң… moveToNextDay [$newStatus]: streak=$newStreakвҶ’$newStreak, " +
                    "planDay=$oldPlanDayвҶ’$newPlanDay, xp=+$xpToBeAwarded(вҶ’$newXp), " +
                    "level=$newLevel, cals=$caloriesBurned, freezeUsed=${newFreezes != oldFreezes}")
                null
            }.await()
            resultStreak
        } catch (e: Exception) {
            Log.e("GamificationRepo", "вқҢ moveToNextDay spodletel: ${e.message}", e)
            // Faza 31.6 avdit: vrnemo -1 (ne 0) kot ekspliciten signal napake.
            // 0 je legitimna vrednost de-dup preskakovanj; -1 nedvoumno pomeni "Firestore je spodletel".
            // VM preverja `takeIf { it > 0 }` вҶ’ -1 bo pravilno filtiran kot napaka.
            -1
        }
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    // runMidnightStreakCheck вҖ” Strogi statusni check za vДҚerajЕЎnji dan
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    override suspend fun runMidnightStreakCheck() {
        val userRef      = FirestoreHelper.getCurrentUserDocRef() ?: return
        val yesterdayStr = getYesterdayStr()

        try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)
                @Suppress("UNCHECKED_CAST")
                val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()

                val yesterdayStatus = UserDayStatus.fromFirestore(dailyHistory[yesterdayStr]?.toString())
                val safeStatuses    = setOf(
                    UserDayStatus.WORKOUT_DONE, UserDayStatus.REST_WORKOUT_DONE,
                    UserDayStatus.REST_DAY_DONE, UserDayStatus.FROZEN
                )
                if (yesterdayStatus in safeStatuses) {
                    Log.d("GamificationRepo", "вң… Midnight check: vДҚeraj ($yesterdayStr) = '$yesterdayStatus' вҖ” ni kazni.")
                    return@runTransaction null
                }

                Log.d("GamificationRepo", "вҡ пёҸ Midnight check: vДҚeraj ($yesterdayStr) = '$yesterdayStatus' вҶ’ kazen.")
                val currentFreezes = (snapshot.getLong("streak_freezes") ?: 0L).toInt()
                if (currentFreezes > 0) {
                    transaction.update(userRef, mapOf(
                        "streak_freezes"             to (currentFreezes - 1),
                        "dailyHistory.$yesterdayStr" to UserDayStatus.FROZEN.firestoreValue
                    ))
                } else {
                    transaction.update(userRef, mapOf(
                        "streak_days"                to 0,
                        "dailyHistory.$yesterdayStr" to UserDayStatus.MISSED.firestoreValue
                    ))
                }
                null
            }.await()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "PolnoДҚni streak check je spodletel.", e)
        }
    }
}

package com.example.myapplication.data.gamification

import android.util.Log
import com.example.myapplication.data.UserProfile
import com.example.myapplication.domain.gamification.GamificationRepository
import com.example.myapplication.domain.gamification.GamificationState
import com.example.myapplication.domain.model.UserDayStatus
import com.example.myapplication.data.store.FirestoreHelper
import com.google.firebase.firestore.SetOptions
import kotlinx.coroutines.tasks.await
import kotlinx.datetime.Clock
import kotlinx.datetime.DateTimeUnit
import kotlinx.datetime.TimeZone
import kotlinx.datetime.minus
import kotlinx.datetime.toLocalDateTime

/**
 * Zlata koda - KMP ready Firestore implementacija za Gamification.
 * NIMA NITI ENE SharedPreferences ODVISNOSTI.
 *
 * Faza 21: Unified moveToNextDay() nadomeЕЎДҚa processActivityCompletion() + updateStreak().
 * - Ena atomarna Firestore transakcija za VSE poti aktivnostnega zakljuДҚka
 * - getYesterdayStr() DST-safe kotlinx.datetime algebra
 * - UserDayStatus tipsko-varni enum nadomeЕЎДҚa raztresene String konstante
 */
class FirestoreGamificationRepository : GamificationRepository {

    private val db get() = FirestoreHelper.getDb()

    private fun getTodayStr(): String =
        Clock.System.now().toLocalDateTime(TimeZone.currentSystemDefault()).date.toString()

    /** DST-safe izraДҚun vДҚerajЕЎnjega datuma prek kotlinx.datetime algebre. */
    private fun getYesterdayStr(): String =
        Clock.System.now()
            .toLocalDateTime(TimeZone.currentSystemDefault())
            .date.minus(1, DateTimeUnit.DAY).toString()

    private fun getTodayEpoch(): Long =
        Clock.System.now()
            .toLocalDateTime(TimeZone.currentSystemDefault())
            .date.toEpochDays().toLong()

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    // awardXP вҖ” za neodvisne klice (login, plan, itd.)
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    override suspend fun awardXP(amount: Int, reason: String) {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return
        try {
            db.runTransaction { transaction ->
                val snapshot  = transaction.get(userRef)
                val currentXp = snapshot.getLong("xp")?.toInt() ?: 0
                val newXp     = currentXp + amount
                val newLevel  = UserProfile.calculateLevel(newXp)
                transaction.set(userRef, mapOf("xp" to newXp, "level" to newLevel), SetOptions.merge())
                val logRef = userRef.collection("xp_history").document()
                transaction.set(logRef, mapOf(
                    "amount" to amount, "reason" to reason, "date" to getTodayStr(),
                    "timestamp" to Clock.System.now().toEpochMilliseconds(),
                    "xpAfter" to newXp, "levelAfter" to newLevel
                ))
            }.await()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "Napaka pri beleЕҫenju XP-ja", e)
        }
    }

    override suspend fun getCurrentStreak(): Int {
        // Faza 34 вҖ” HIGH-01 Fix: Propagiraj izjemo navzgor namesto tihega 0.
        // PrejЕЎnji catch { 0 } je ob mreЕҫni napaki vrnil streak=0, kar je UI potencialno
        // resetiral streak na niДҚlo brez dejanske spremembe v Firestoreu.
        val userRef = FirestoreHelper.getCurrentUserDocRef()
            ?: throw IllegalStateException("Uporabnik ni prijavljen вҖ” getCurrentStreak zahteva veljavno sejo.")
        return userRef.get().await().getLong("streak_days")?.toInt() ?: 0
    }

    override suspend fun markRestDayPending() {
        val userRef  = FirestoreHelper.getCurrentUserDocRef() ?: return
        val todayStr = getTodayStr()
        try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)
                @Suppress("UNCHECKED_CAST")
                val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()
                val existing = UserDayStatus.fromFirestore(dailyHistory[todayStr]?.toString())
                // Idempotentno вҖ” ne prepiЕЎi zakljuДҚenih statusov
                if (existing.isDoneToday) return@runTransaction null
                transaction.update(userRef, mapOf(
                    "dailyHistory.$todayStr" to UserDayStatus.REST_DAY_PENDING.firestoreValue
                ))
                null
            }.await()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "Napaka pri markRestDayPending()", e)
        }
    }

    override suspend fun getTodayStatus(): UserDayStatus {
        // Faza 34 вҖ” HIGH-02 Fix: Propagiraj izjemo namesto tihega WORKOUT_PENDING fallback-a.
        // Tihi fallback je bil nevaren: auth/mreЕҫna napaka bi sistema pustila misliti,
        // da vadba danes ni bila opravljena, kar bi dovolilo duplikatni zapis streaka.
        val userRef = FirestoreHelper.getCurrentUserDocRef()
            ?: throw IllegalStateException("Uporabnik ni prijavljen вҖ” getTodayStatus zahteva veljavno sejo.")
        val snapshot = userRef.get().await()
        @Suppress("UNCHECKED_CAST")
        val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()
        return UserDayStatus.fromFirestore(dailyHistory[getTodayStr()]?.toString())
    }

    override suspend fun consumeStreakFreeze(): Boolean {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return false
        return try {
            // Faza 34 вҖ” CRIT-03 Fix: Transakcija neposredno vrne Boolean вҖ” brez externalne
            // mutable var `consumed`, ki bi bila ranljiva na retry-prone lambda izvedbo.
            val consumed: Boolean = db.runTransaction { transaction ->
                val snap = transaction.get(userRef)
                val curr = snap.getLong("streak_freezes")?.toInt() ?: 0
                if (curr > 0) {
                    transaction.update(userRef, "streak_freezes", curr - 1)
                    true   // atomarno: porabi in vrni true
                } else {
                    false  // ni zamrznitev na voljo
                }
            }.await() ?: false
            consumed
        } catch (e: Exception) { false }
    }

    override suspend fun logBurnedCalories(todayStr: String, calories: Double) {
        try {
            val userRef     = FirestoreHelper.getCurrentUserDocRef() ?: return
            val dailyLogRef = db.collection("dailyLogs").document(todayStr)
            db.runTransaction { transaction ->
                val snap     = transaction.get(dailyLogRef)
                val existing = (snap.get("burnedCalories") as? Number)?.toDouble() ?: 0.0
                transaction.set(
                    dailyLogRef,
                    mapOf("burnedCalories" to existing + calories, "userId" to userRef.id),
                    SetOptions.merge()
                )
                null
            }.await()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "logBurnedCalories failed: ${e.message}")
        }
    }

    override suspend fun getGamificationState(): GamificationState {
        return try {
            val userRef  = FirestoreHelper.getCurrentUserDocRef() ?: return GamificationState()
            val snapshot = userRef.get().await()
            val weeklyTarget   = snapshot.getLong("weekly_target")?.toInt() ?: 0
            val workoutDone    = getTodayStatus().isDoneToday
            GamificationState(weeklyTarget = weeklyTarget, workoutDoneToday = workoutDone)
        } catch (e: Exception) { GamificationState() }
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    // moveToNextDay вҖ” SSOT za VSE aktivnostne zakljuДҚke (Faza 21)
    //
    // ENA atomarna Firestore transakcija za:
    //   в‘  De-duplikacija (ne prepiЕЎe WORKOUT_DONE z niЕҫjo prioriteto)
    //   в‘Ў Streak izraДҚun (epoch-based, Streak Freeze podpora)
    //   в‘ў plan_day +1 (samo kadar incrementPlanDay=true)
    //   в‘Ј XP + Level atomarno
    //   в‘Ө dailyHistory vpis z UserDayStatus.firestoreValue
    //   в‘Ҙ burnedCalories v dailyLogs (Nutrition bridge)
    //
    // ДҢe transakcija SPODLETI вҶ’ Room ni posodobljena (callerji prejmejo 0).
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    override suspend fun moveToNextDay(
        newStatus: UserDayStatus,
        xpToBeAwarded: Int,
        xpReason: String,
        caloriesBurned: Double,
        incrementPlanDay: Boolean
    ): Int {
        // Samo zakljuДҚitveni statusi so dovoljeni
        require(newStatus.isDoneToday) {
            "moveToNextDay zahteva zakljuДҚitveni status (WORKOUT_DONE, REST_DAY_DONE, REST_WORKOUT_DONE)."
        }

        val userRef    = FirestoreHelper.getCurrentUserDocRef() ?: return 0
        val todayStr   = getTodayStr()
        val todayEpoch = getTodayEpoch()
        val nowMillis  = Clock.System.now().toEpochMilliseconds()
        var resultStreak = 0

        return try {
            db.runTransaction { transaction ->
                // в”Җв”Җ READ faza в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                val snapshot = transaction.get(userRef)

                @Suppress("UNCHECKED_CAST")
                val dailyHistory   = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()
                val existingStatus = UserDayStatus.fromFirestore(dailyHistory[todayStr]?.toString())

                // De-dup: WORKOUT_DONE je najviЕЎja prioriteta, ne prepiЕЎi ga
                if (existingStatus == UserDayStatus.WORKOUT_DONE || existingStatus == newStatus) {
                    Log.d("GamificationRepo", "moveToNextDay: $todayStr Еҫe '$existingStatus' вҖ” de-dup preskoДҚek.")
                    resultStreak = snapshot.getLong("streak_days")?.toInt() ?: 0
                    return@runTransaction null
                }

                val oldStreak     = (snapshot.getLong("streak_days")         ?: 0L).toInt()
                val oldLastEpoch  =  snapshot.getLong("last_activity_epoch") ?: 0L
                val oldPlanDay    = (snapshot.getLong("plan_day")            ?: 1L).toInt()
                val oldFreezes    = (snapshot.getLong("streak_freezes")      ?: 0L).toInt()
                val currentXp     = (snapshot.getLong("xp")                  ?: 0L).toInt()

                // Burned calories za Nutrition bridge
                val dailyLogRef = db.collection("dailyLogs").document(todayStr)
                val logSnapshot = if (caloriesBurned > 0.0) transaction.get(dailyLogRef) else null
                val existingCals = (logSnapshot?.get("burnedCalories") as? Number)?.toDouble() ?: 0.0

                // в”Җв”Җ Streak izraДҚun в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                val dayDiff    = todayEpoch - oldLastEpoch
                var newFreezes = oldFreezes
                val newStreak: Int = when {
                    !newStatus.contributesToStreak -> oldStreak          // REST_WORKOUT_DONE = ohrani
                    oldLastEpoch == 0L             -> 1                  // Prva aktivnost kdajkoli
                    dayDiff == 0L                  -> oldStreak          // Isti dan (de-dup zgoraj bi ujel)
                    dayDiff == 1L                  -> oldStreak + 1      // VДҚeraj aktiven вҶ’ podaljЕЎaj
                    oldFreezes > 0                 -> {                  // Vrzel > 1 dan вҶ’ preveri Freeze
                        newFreezes = oldFreezes - 1
                        Log.d("GamificationRepo", "вқ„пёҸ moveToNextDay: Streak Freeze porabljen! Ostalo: $newFreezes")
                        oldStreak
                    }
                    else -> 1                                            // Ni freeze вҶ’ ponastavi na 1
                }
                resultStreak = newStreak

                // в”Җв”Җ Plan day napredovanje в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                val newPlanDay = if (incrementPlanDay) oldPlanDay + 1 else oldPlanDay

                // в”Җв”Җ XP + Level в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                val newXp    = currentXp + xpToBeAwarded
                val newLevel = UserProfile.calculateLevel(newXp)

                // в”Җв”Җ WRITE faza в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                val userUpdates = mutableMapOf<String, Any>(
                    "streak_days"             to newStreak,
                    "plan_day"                to newPlanDay,
                    "last_activity_epoch"     to todayEpoch,
                    "last_streak_update_date" to todayStr,
                    "dailyHistory.$todayStr"  to newStatus.firestoreValue,
                    "xp"                      to newXp,
                    "level"                   to newLevel
                )
                if (newFreezes != oldFreezes) userUpdates["streak_freezes"] = newFreezes
                transaction.update(userRef, userUpdates)

                // XP history log
                if (xpToBeAwarded > 0) {
                    val xpLogRef = userRef.collection("xp_history").document()
                    transaction.set(xpLogRef, mapOf(
                        "amount" to xpToBeAwarded, "reason" to xpReason,
                        "date" to todayStr, "timestamp" to nowMillis,
                        "xpAfter" to newXp, "levelAfter" to newLevel
                    ))
                }

                // Burned calories вҶ’ Nutrition bridge
                if (caloriesBurned > 0.0 && logSnapshot != null) {
                    transaction.set(
                        dailyLogRef,
                        mapOf("burnedCalories" to existingCals + caloriesBurned, "userId" to userRef.id),
                        SetOptions.merge()
                    )
                }

                Log.d("GamificationRepo",
                    "вң… moveToNextDay [$newStatus]: streak=$newStreakвҶ’$newStreak, " +
                    "planDay=$oldPlanDayвҶ’$newPlanDay, xp=+$xpToBeAwarded(вҶ’$newXp), " +
                    "level=$newLevel, cals=$caloriesBurned, freezeUsed=${newFreezes != oldFreezes}")
                null
            }.await()
            resultStreak
        } catch (e: Exception) {
            Log.e("GamificationRepo", "вқҢ moveToNextDay spodletel: ${e.message}", e)
            // Faza 31.6 avdit: vrnemo -1 (ne 0) kot ekspliciten signal napake.
            // 0 je legitimna vrednost de-dup preskakovanj; -1 nedvoumno pomeni "Firestore je spodletel".
            // VM preverja `takeIf { it > 0 }` вҶ’ -1 bo pravilno filtiran kot napaka.
            -1
        }
    }

    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    // runMidnightStreakCheck вҖ” Strogi statusni check za vДҚerajЕЎnji dan
    // в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    override suspend fun runMidnightStreakCheck() {
        val userRef      = FirestoreHelper.getCurrentUserDocRef() ?: return
        val yesterdayStr = getYesterdayStr()

        try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)
                @Suppress("UNCHECKED_CAST")
                val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()

                val yesterdayStatus = UserDayStatus.fromFirestore(dailyHistory[yesterdayStr]?.toString())
                val safeStatuses    = setOf(
                    UserDayStatus.WORKOUT_DONE, UserDayStatus.REST_WORKOUT_DONE,
                    UserDayStatus.REST_DAY_DONE, UserDayStatus.FROZEN
                )
                if (yesterdayStatus in safeStatuses) {
                    Log.d("GamificationRepo", "вң… Midnight check: vДҚeraj ($yesterdayStr) = '$yesterdayStatus' вҖ” ni kazni.")
                    return@runTransaction null
                }

                Log.d("GamificationRepo", "вҡ пёҸ Midnight check: vДҚeraj ($yesterdayStr) = '$yesterdayStatus' вҶ’ kazen.")
                val currentFreezes = (snapshot.getLong("streak_freezes") ?: 0L).toInt()
                if (currentFreezes > 0) {
                    transaction.update(userRef, mapOf(
                        "streak_freezes"             to (currentFreezes - 1),
                        "dailyHistory.$yesterdayStr" to UserDayStatus.FROZEN.firestoreValue
                    ))
                } else {
                    transaction.update(userRef, mapOf(
                        "streak_days"                to 0,
                        "dailyHistory.$yesterdayStr" to UserDayStatus.MISSED.firestoreValue
                    ))
                }
                null
            }.await()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "PolnoДҚni streak check je spodletel.", e)
        }
    }
}

